"""Save simplified JSON for threads that were extracted by background agents."""
import json
import os
import re

# Agent results - manually extracted from their outputs
# Each entry: threadId, subject, messages list
agent_threads = [
    {"threadId": "14d31b926c52515f", "messages": [
        {"messageId": "14d31b926c52515f", "headers": {"From": "Cosmo Harrigan <cosmo.harrigan@singularityu.org>", "Date": "Thu, 7 May 2015 21:12:04 -0700", "Subject": "[opencog-dev] Markov chain demo syntax"}, "body": "I was looking through the Markov chain demo. Some questions occurred about the atomspace syntax. It seems the idea here is to use a ListLink to define a pair (variable, value) using an AnchorNode."},
        {"messageId": "14d31f540a5052a4", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Fri, 8 May 2015 00:17:23 -0500", "Subject": "[opencog-dev] Re: Markov chain demo syntax"}, "body": "No particular reason. I avoided them because I did not want to collide with PLN or other subsystems. I picked the AnchorNode because its just different from everything else, no risk of confusion. I plan to start sticking FSMs into the atomspace, to do robot behaviors, and if PLN starts deducing unexpected things and garbaging up the FSM state, that would be bad."},
        {"messageId": "14d3211f8bcdd1db", "headers": {"From": "Cosmo Harrigan <cosmo.harrigan@singularityu.org>", "Date": "Thu, 7 May 2015 22:49:02 -0700", "Subject": "Re: [opencog-dev] Re: Markov chain demo syntax"}, "body": "It might be helpful to share a common notation between these different systems."},
        {"messageId": "14d35365f32758ba", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Fri, 8 May 2015 15:27:21 -0500", "Subject": "Re: [opencog-dev] Re: Markov chain demo syntax"}, "body": "The anchor was invented as a parallel/concurrent-processing rendezvous point. When one process finishes some work, it drops off its result by attaching it to an anchor. Then, other agents can look for new work attached to anchor, then detach it, and do their processing on it. In an actor model, the sender attaches things to an anchor, the receiver unhooks from it."},
        {"messageId": "14d3684afa527ecc", "headers": {"From": "Ben Goertzel <ben@goertzel.org>", "Date": "Sat, 9 May 2015 10:32:53 +0800", "Subject": "Re: [opencog-dev] Re: Markov chain demo syntax"}, "body": "The semantics of SubsetLink aka ExtensionalInheritanceLink is that the strength of the link is EXACTLY a conditional probability. PLN comes with specific ways of measuring confidence. We have discussed bifurcating SimpleTruthValue into SimpleFuzzyTruthValue and SimpleProbabilisticTruthValue."},
        {"messageId": "14d3a9a34afee97e", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Sat, 9 May 2015 16:34:31 -0500", "Subject": "Re: [opencog-dev] Re: Markov chain demo syntax"}, "body": "My concern is having two different algorithms modifying the contents of the atomspace at the same time. If one algo is PLN, and another is performing specific TV calculations, then one may create TVs that are invalid from the other point of view."},
        {"messageId": "14d3eab6d484e4e9", "headers": {"From": "Ben Goertzel <ben@goertzel.org>", "Date": "Mon, 11 May 2015 00:32:10 +0800", "Subject": "Re: [opencog-dev] Re: Markov chain demo syntax"}, "body": "Having multiple algorithms modifying the Atomspace at the same time is exactly what OpenCog is intended for... However, it needs to be done thoughtfully. I suggest we think through how to make these algorithms work together."},
        {"messageId": "14d475985dfaaabe", "headers": {"From": "Nil Geisweiller <ngeiswei@googlemail.com>", "Date": "Tue, 12 May 2015 10:59:13 +0200", "Subject": "Re: [opencog-dev] Re: Markov chain demo syntax"}, "body": "That is why the semantics of things should be generally coherent with PLN. Once we have the type system supporting monads we can easily differentiate pure vs side-effect structures."}
    ]},
    {"threadId": "14bc52068d70cde9", "messages": [
        {"messageId": "14bc52068d70cde9", "headers": {"From": "Douglas Chorpita via opencog <opencog@googlegroups.com>", "Date": "Thu, 26 Feb 2015 01:03:28 -0800", "Subject": "[opencog-dev] atomspace 3D-viewer"}, "body": "Here is the latest version of the 3D viewer. Hit A while holding the mouse cursor over an atom to grab it. Hit Q to return to orbit controls."},
        {"messageId": "14bc6b0d32a7edc1", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Thu, 26 Feb 2015 10:20:29 -0600", "Subject": "Re: [opencog-dev] atomspace 3D-viewer"}, "body": "So is this code in github somewhere? With instructions for how to set it up?"},
        {"messageId": "14c081661d10a982", "headers": {"From": "Douglas Chorpita via opencog <opencog@googlegroups.com>", "Date": "Wed, 11 Mar 2015 02:07:03 -0700", "Subject": "Re: [opencog-dev] atomspace 3D-viewer"}, "body": "Sorry I was on vacation. I plan to get more code pushed to github soon."},
        {"messageId": "14c0820587493d81", "headers": {"From": "Ben Goertzel <ben@goertzel.org>", "Date": "Wed, 11 Mar 2015 17:17:57 +0800", "Subject": "Re: [opencog-dev] atomspace 3D-viewer"}, "body": "We have someone George in the HK office from now thru June 30 working full-time on the visualizer. So if you feel like coming out to HK to play with visualization of the Atomspace, you would have a playmate."},
        {"messageId": "14ca8bff8e857e82", "headers": {"From": "Douglas Chorpita via opencog <opencog@googlegroups.com>", "Date": "Sat, 11 Apr 2015 06:51:33 -0700", "Subject": "Re: [opencog-dev] atomspace 3D-viewer"}, "body": "Ben has encouraged me to come to Hong Kong to work with George and Amen on 3D visualization. I may come in mid May."},
        {"messageId": "14ca8f452e6627d2", "headers": {"From": "Aurelien RAINONE <aurelien.rainone@gmail.com>", "Date": "Sat, 11 Apr 2015 16:48:23 +0200", "Subject": "Re: [opencog-dev] atomspace 3D-viewer"}, "body": "I am currently working on the opencog workbench, a modular web application in which you can add modules to monitor and control various opencog subsystems. The atom space visualizer will eventually be one of these modules."},
        {"messageId": "14d2f1d3deeebcb6", "headers": {"From": "Aurelien RAINONE <aurelien.rainone@gmail.com>", "Date": "Thu, 7 May 2015 18:01:42 +0200", "Subject": "Re: [opencog-dev] atomspace 3D-viewer"}, "body": "I came up with the modular single page application some of us were talking about for the opencog workbench. Still have some things to work on: write docs, simplify the build system."}
    ]},
    {"threadId": "14bfea9000926aa8", "messages": [
        {"messageId": "14bfea9000926aa8", "headers": {"From": "sumit.sourabh@gmail.com", "Date": "Mon, 9 Mar 2015 06:10:28 -0700", "Subject": "[opencog-dev] Planning via Temporal logic and Consistency checking - GSoC 2015"}, "body": "I am a final year PhD student at Institute for Logic, Language and Computation, University of Amsterdam. I have a strong background in mathematical logic. I was interested in the Planning via Temporal logic project."},
        {"messageId": "14c04bdd3f50b217", "headers": {"From": "Ben Goertzel <ben@goertzel.org>", "Date": "Wed, 11 Mar 2015 01:31:25 +0800", "Subject": "Re: [opencog-dev] Planning via Temporal logic and Consistency checking - GSoC 2015"}, "body": "Your background certainly sounds relevant. I think we could use your expertise in the PLN component of OpenCog. I wonder if a good project might be to implement some modal logic rules and truth value formulas in PLN. This would be fairly light on the software engineering and heavy on the logic."},
        {"messageId": "14c28284c7094e18", "headers": {"From": "Ben Goertzel <ben@goertzel.org>", "Date": "Tue, 17 Mar 2015 22:34:30 +0800", "Subject": "Re: [opencog-dev] Planning via Temporal logic and Consistency checking - GSoC 2015"}, "body": "I think the general approach in the referenced AAAI 2007 paper could be adapted to OpenCog, including the idea of using a sampling algorithm to estimate truth values. This seems a promising and feasible direction for a GSoC project."},
        {"messageId": "14cffa6e7b62f9c3", "headers": {"From": "Sumit Sourabh <sumit.sourabh@gmail.com>", "Date": "Tue, 28 Apr 2015 03:51:08 -0700", "Subject": "Re: [opencog-dev] Planning via Temporal logic and Consistency checking - GSoC 2015"}, "body": "You would be happy to know that my proposal got accepted for GSoC! My mentor is Matt Ikle."},
        {"messageId": "14d0300287015820", "headers": {"From": "Matthew Ikle <matt.ikle@gmail.com>", "Date": "Wed, 29 Apr 2015 10:27:20 +0800", "Subject": "Re: [opencog-dev] Planning via Temporal logic and Consistency checking - GSoC 2015"}, "body": "Welcome to the OpenCog team! As Ben mentioned, you likely know more about modal logic than anyone else on the team."}
    ]},
    {"threadId": "151e7412caaf2ec9", "messages": [
        {"messageId": "151e7412caaf2ec9", "headers": {"From": "Fredy <fredyvilla@gmail.com>", "Date": "Sun, 27 Dec 2015 22:23:04 -0800", "Subject": "[opencog-dev] Achieving Exciting Demonstrability - Minecraft Bot Roadmap"}, "body": "After reading Ben development roadmap and catching-up with the opencog-to-minecraft project, I have been thinking about a roadmap. Phase 1: Minimum Survival. Phase 2: Building. Phase 3: Intelligent Behavior."},
        {"messageId": "151e75a13e5580bc", "headers": {"From": "Ben Goertzel <ben@goertzel.org>", "Date": "Mon, 28 Dec 2015 14:50:17 +0800", "Subject": "Re: [opencog-dev] Achieving Exciting Demonstrability - Minecraft Bot Roadmap"}, "body": "This is great, thanks! Perhaps you can paste the ideas onto a wiki page so it can be collectively edited. One hope is that this project may serve as a fun way for newbies to get involved with OpenCog."},
        {"messageId": "151eeb9f5dadca99", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Tue, 29 Dec 2015 11:12:02 -0600", "Subject": "Re: [opencog-dev] Achieving Exciting Demonstrability - Minecraft Bot Roadmap"}, "body": "Wiki editing is partly disabled due to spambots. Try it, tell me which step blocks you and me or amen can enable the account."}
    ]},
    {"threadId": "151e70039fc670ab", "messages": [
        {"messageId": "151e70039fc670ab", "headers": {"From": "Ben Goertzel <ben@goertzel.org>", "Date": "Mon, 28 Dec 2015 13:12:08 +0800", "Subject": "[opencog-dev] Event boundary recognition in OpenCog: Atomese representation issues"}, "body": "I have written thoughts about how to handle event boundary recognition using Atomese representations, GSNs, etc. This is an extension of my prior suggestions of how to wrap up deep learning algorithms in OpenCog."},
        {"messageId": "151ef53dfbf8a836", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Tue, 29 Dec 2015 14:00:07 -0600", "Subject": "[opencog-dev] Re: Event boundary recognition in OpenCog"}, "body": "The event-detection problem reminds me of a different AI problem. Suppose you have football players on a field, and you want to figure out the play type from their movement tracks. The input is a collection of 2D tracks."},
        {"messageId": "151f0f3bc64c601e", "headers": {"From": "Ben Goertzel <ben@goertzel.org>", "Date": "Wed, 30 Dec 2015 11:34:41 +0800", "Subject": "[opencog-dev] Re: Event boundary recognition in OpenCog"}, "body": "The problem I was aiming to solve FIRST was not identifying or clustering events, but merely recognizing the natural beginnings and endings of events. It seems that event boundaries are characterized by discontinuity of predictability. I propose using multivariate permutation entropy."},
        {"messageId": "151f67b0ab48277b", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Wed, 30 Dec 2015 23:20:16 -0600", "Subject": "[opencog-dev] Re: Event boundary recognition in OpenCog"}, "body": "Segmentation is a necessary starting point, and permutation entropy sounds quite reasonable. I started a wiki page on Motion analysis. Re Atomese: the standard syntax for DefineSchema is DefineLink with DefinedSchema and Lambda."},
        {"messageId": "152112621dc13faf", "headers": {"From": "Nil Geisweiller via opencog <opencog@googlegroups.com>", "Date": "Tue, 5 Jan 2016 11:37:33 +0200", "Subject": "Re: [opencog-dev] Re: Event boundary recognition in OpenCog"}, "body": "I am OK to use nullary DefinedSchemaNode as constant, and have DefineLink only work on DefinedSchemaNode, DefinedPredicateNode and DefinedTypeNode. The current type system over defined schema node is really cool!"}
    ]},
    {"threadId": "15023a9412a3073c", "messages": [
        {"messageId": "15023a9412a3073c", "headers": {"From": "Amirouche Boubekki <amirouche.boubekki@gmail.com>", "Date": "Thu, 01 Oct 2015 13:48:14 +0000", "Subject": "[opencog-dev] Culturia implementation description (ref: PredicateLink Proposal)"}, "body": "This is mildly related to the discussion about PredicateLink. I experimented with hypergraph databases and wanted to see how atomspace schema compares to graphdb."},
        {"messageId": "1502ae817d2d6a54", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Fri, 2 Oct 2015 18:34:03 -0500", "Subject": "Re: [opencog-dev] Culturia implementation description"}, "body": "For all practical purposes, the atomspace just stores graphs, and the word hypergraph does nothing but confuse. Actually, the atomspace stores forests which are collections of trees. It does NOT really store graphs in general."},
        {"messageId": "15030401538ef783", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Sat, 3 Oct 2015 19:28:16 -0500", "Subject": "Re: [opencog-dev] Culturia implementation description"}, "body": "The pattern matcher can handle simple and complex PLN searches. The question is how to do this efficiently. Its NP-complete in general; the atomspace has some support for indexing, but this is still very much a work in progress."},
        {"messageId": "15036af7753b7b84", "headers": {"From": "Nil Geisweiller via opencog <opencog@googlegroups.com>", "Date": "Mon, 5 Oct 2015 09:27:56 +0300", "Subject": "Re: [opencog-dev] Culturia implementation description"}, "body": "Note that you probably want to have the entity as member, not the inheritance link. The PM query for that would use an AndLink with PredicateLink and InheritanceLink."}
    ]},
    {"threadId": "14f12e83b3e1be70", "messages": [
        {"messageId": "14f12e83b3e1be70", "headers": {"From": "Terry Woodward <redhat707@gmail.com>", "Date": "Sun, 9 Aug 2015 07:40:49 -0700", "Subject": "[opencog-dev] Article: MIT claims to have found a language universal"}, "body": "MIT article with DLM concept may be of interest."},
        {"messageId": "14f1321178b4c4fa", "headers": {"From": "Ben Goertzel <ben@goertzel.org>", "Date": "Sun, 9 Aug 2015 18:42:57 +0300", "Subject": "Re: [opencog-dev] Article: MIT claims to have found a language universal"}, "body": "The result is nice but very unsurprising and certainly provides no evidence for a Chomsky-style principles and parameters approach to linguistics. The universal they propose would seem a natural consequence of any language designed for use by agents whose working memories have some sort of rapid decay function."},
        {"messageId": "14f13fff04810a86", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Sun, 9 Aug 2015 14:46:03 -0500", "Subject": "Re: [opencog-dev] Article: MIT claims to have found a language universal"}, "body": "The idea of dependency-length minimization is old -- dating back at least 30 years, and was one of the ideas that influenced the development of link-grammar. Other measures proposed include graph centrality and hubiness, with arguments that hubiness is a more accurate measure."},
        {"messageId": "14f23bd99f5f254b", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Wed, 12 Aug 2015 16:07:29 -0500", "Subject": "Re: [Link Grammar] Fwd: [opencog-dev] Article: MIT claims to have found a language universal"}, "body": "Hubiness may be a better model of sentence complexity than mean dependency distance. Extensive bibliography on dependency-length minimization: idea traced back to Yngve 1960. Key refs include Temperley 2008, Park and Levy 2009, Gibson 2000, Haitao Liu 2008, Hawkins 1994 and 2004."},
        {"messageId": "14f2785b5d6a6d7b", "headers": {"From": "Richard Hudson <r.hudson@ucl.ac.uk>", "Date": "Thu, 13 Aug 2015 15:45:03 +0100", "Subject": "Re: [Link Grammar] Fwd: [opencog-dev] Article: MIT claims to have found a language universal"}, "body": "Surprised if hubiness measures processing difficulty better than dependency length because degree without mention of order does not distinguish DHD from DDH. Dependency length too crude, needs sophistication."},
        {"messageId": "14f28010fef69caa", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Thu, 13 Aug 2015 11:59:40 -0500", "Subject": "Re: [Link Grammar] Fwd: [opencog-dev] Article: MIT claims to have found a language universal"}, "body": "Multiple issues make this hard to sort out. Even if a formula is found, the original claim of psychological plausibility means lab experiments still have to be designed and run. This seems like a good-sized research program, not something to be quickly knocked off."}
    ]},
    {"threadId": "14e25d53c74ad79b", "messages": [
        {"messageId": "14e25d53c74ad79b", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Wed, 24 Jun 2015 08:50:06 -0500", "Subject": "[opencog-dev] automated discovery of grammatical classes"}, "body": "See the attached PDF, it explains some of the ideas more clearly. The very next goal is to explore the different similarity metrics on your database of real data, and see how well the different metrics might do. This will require writing a bunch of code and generating more lists, more graphs."},
        {"messageId": "14e2d82b98000824", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Thu, 25 Jun 2015 20:36:55 -0500", "Subject": "Re: [opencog-dev] automated discovery of grammatical classes"}, "body": "The attached includes formulas for the frequency and the MI of disjuncts. In addition to the data collection and analysis, new code is needed to perform the actual groupings of words into classes, and that the merge discovery process has to be able to merge words into existing classes."},
        {"messageId": "14e2e7236d5fcbe1", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Fri, 26 Jun 2015 13:58:08 +0800", "Subject": "Re: [opencog-dev] automated discovery of grammatical classes"}, "body": "A period denotes the end of a speech act, and it is a valid part of language. It has a real semantic meaning. Just like some words only occur at the beginning of sentences, other words occur only at the end."},
        {"messageId": "14e4411d10d5906d", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Tue, 30 Jun 2015 18:44:33 +0800", "Subject": "Re: [opencog-dev] automated discovery of grammatical classes"}, "body": "A vector space is a set of objects with a single floating point number associated with each element of the set. The set of objects is called the basis. Each disjunct is a basis vector. A word-vector is constructed by listing how many times each disjunct occurs with that word."}
    ]},
    {"threadId": "14d3088ce7b87179", "messages": [
        {"messageId": "14d3088ce7b87179", "headers": {"From": "Curtis M. Faith <curtis.m.faith@gmail.com>", "Date": "Fri, 8 May 2015 01:22:00 -0700", "Subject": "[opencog-dev] Cogserver fails to load python atomspace module on fresh build"}, "body": "Cogserver fails to load python atomspace module on fresh build. The error is related to PythonModule import."}
    ]}
]

for t in agent_threads:
    path = "raw_data_exports/gmail_raw_2015/" + t["threadId"] + ".json"
    if not os.path.exists(path):
        with open(path, "w") as f:
            json.dump(t, f, indent=2)
        print("Saved " + t["threadId"])
    else:
        print("Already exists: " + t["threadId"])
